package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Constructor;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setup() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testParseReturnsCSVParser() throws Exception {
        Reader reader = mock(Reader.class);

        // Use reflection to create a mock CSVParser instance
        CSVParser mockParser = mock(CSVParser.class);

        // Use reflection to replace constructor call
        CSVFormat spyFormat = spy(csvFormat);
        doReturn(mockParser).when(spyFormat).parseInternal(any());

        CSVParser parser = spyFormat.parse(reader);

        assertNotNull(parser);
        assertEquals(mockParser, parser);
    }

    @Test
    void testParseWithNullReaderThrowsNPE() {
        assertThrows(NullPointerException.class, () -> csvFormat.parse(null));
    }

    @Test
    void testParseCreatesCSVParserWithThisInstance() throws Exception {
        Reader reader = mock(Reader.class);

        // Use reflection to intercept CSVParser creation
        Constructor<CSVParser> constructor = CSVParser.class.getDeclaredConstructor(Reader.class, CSVFormat.class);
        constructor.setAccessible(true);

        CSVParser parser = constructor.newInstance(reader, csvFormat);
        assertNotNull(parser);
    }

    // Add a helper method in CSVFormatTest to simulate parseInternal for mocking
    private CSVParser parseInternal(Reader in) throws IOException {
        return new CSVParser(in, csvFormat);
    }
}
